import{c as i,Q as o,j as r,m as t}from"./chunks/framework.D0LfRJ4P.js";const y=JSON.parse('{"title":"Kyverno / Policy Reporter","description":"","frontmatter":{},"headers":[],"relativePath":"showcases/kyverno.md","filePath":"showcases/kyverno.md","lastUpdated":1717660093000}'),a={name:"showcases/kyverno.md"};function s(l,e,n,p,c,h){return o(),r("div",null,[...e[0]||(e[0]=[t(`<h1 id="kyverno-policy-reporter" tabindex="-1">Kyverno / Policy Reporter <a class="header-anchor" href="#kyverno-policy-reporter" aria-label="Permalink to &quot;Kyverno / Policy Reporter&quot;">​</a></h1><h3 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h3><p>In this example Kyverno and Policy Reporter incl. UI will be deployed. As an example the default Pod Security Policies are deployed by this script. More details here:</p><ul><li><a href="https://kubernetes.io/docs/concepts/security/pod-security-standards/" target="_blank" rel="noreferrer">https://kubernetes.io/docs/concepts/security/pod-security-standards/</a></li><li><a href="https://kyverno.io/policies/pod-security/" target="_blank" rel="noreferrer">https://kyverno.io/policies/pod-security/</a></li></ul><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><p>You can install Kyverno and the Kyverno Policy Reporter with the following startup command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/kyverno</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup.sh</span></span></code></pre></div><p>The following components are installed with the <em>setup.sh</em>:</p><ul><li>Kyverno is installed via HELM Chart</li><li>Policy Reporter (API, Kyverno Plugin and UI) is installed via HELM Chart</li><li>Example policies deployed - <a href="https://kyverno.io/policies/pod-security/" target="_blank" rel="noreferrer">https://kyverno.io/policies/pod-security/</a><ul><li>You can check this: <code>kubectl get clusterpolicies.kyverno.io</code></li><li>These examples are deployed in <em>Audit</em> mode - you can see failing policies in the Policy Reporter UI, but they are not permitted by Kyverno.</li></ul></li></ul><h3 id="show-policy-reporter-ui" tabindex="-1">Show Policy Reporter UI <a class="header-anchor" href="#show-policy-reporter-ui" aria-label="Permalink to &quot;Show Policy Reporter UI&quot;">​</a></h3><p>The Policy Reporter UI is exposed via Ingress, you can open Policy-Reporter-UI in a browser of your choice: <a href="https://policy-reporter-127-0-0-1.nip.io:8081/#/" target="_blank" rel="noreferrer">https://policy-reporter-127-0-0-1.nip.io:8081/#/</a></p>`,11)])])}const u=i(a,[["render",s]]);export{y as __pageData,u as default};
